// Custom Backstage plugin structure
plugins/
  cost-dashboard/
    src/
      plugin.ts
      components/
        CostOverview.tsx
      api/
        CostClient.ts
    package.json

// plugin.ts
export const costDashboardPlugin = createPlugin({
  id: 'cost-dashboard',
  apis: [
    createApiFactory({
      api: costApiRef,
      deps: { fetchApi: fetchApiRef },
      factory: ({ fetchApi }) =>
        new CostClient({ fetchApi }),
    }),
  ],
});
